/ Games List with Pull to Refreshstruct GamesListView: View {    @Environment(GamesViewModel.self) var viewModel    @Binding var selectedGame: Game?    let selectedSport: Sport  // Passed in from parent        var body: some View {        ScrollView {            // Pull to refresh hint            if viewModel.isLoading {                HStack {                    ProgressView()                        .scaleEffect(0.8)                    Text("Updating...")                        .font(.caption)                        .foregroundColor(.white.opacity(0.7))                }                .padding(.top, 8)            }                        LazyVStack(spacing: 12) {                // Live Games Section                if !viewModel.liveGames.isEmpty {                    GamesSectionHeader(title: "LIVE", count: viewModel.liveGames.count, isLive: true)                    ForEach(viewModel.liveGames) { apiGame in                        let game = convertToGame(apiGame)                        GameCard(game: game)                            .onTapGesture { selectedGame = game }                    }                }                                // Upcoming Games Section                if !viewModel.upcomingGames.isEmpty {                    GamesSectionHeader(title: "UPCOMING", count: viewModel.upcomingGames.count, isLive: false)                    ForEach(viewModel.upcomingGames) { apiGame in                        let game = convertToGame(apiGame)                        GameCard(game: game)                            .onTapGesture { selectedGame = game }                    }                }                                // Completed Games Section                if !viewModel.completedGames.isEmpty {                    GamesSectionHeader(title: "FINAL", count: viewModel.completedGames.count, isLive: false)                    ForEach(viewModel.completedGames) { apiGame in                        let game = convertToGame(apiGame)                        GameCard(game: game)                            .onTapGesture { selectedGame = game }                    }                }                                // Last update time                if !viewModel.apiGames.isEmpty {                    LastUpdateView(date: viewModel.lastUpdate)                }            }            .padding()        }        .refreshable {            await viewModel.refresh(for: selectedSport)        }    }        private func convertToGame(_ apiGame: APIGame) -> Game {        let status: GameStatus        if apiGame.isLive { status = .live }        else if apiGame.isFinal { status = .final }        else { status = .upcoming(time: extractTime(from: apiGame.date)) }                return Game(            homeTeam: apiGame.homeTeam?.team.displayName ?? "Home",            awayTeam: apiGame.awayTeam?.team.displayName ?? "Away",            homeScore: Int(apiGame.homeTeam?.score ?? "0") ?? 0,            awayScore: Int(apiGame.awayTeam?.score ?? "0") ?? 0,            status: status,            quarter: getQuarter(apiGame),            timeRemaining: apiGame.isLive ? apiGame.displayClock : nil,            sport: selectedSport,  // Use the local selectedSport            espnGameId: apiGame.id,            homeLogoURL: apiGame.homeTeam?.team.logo,            awayLogoURL: apiGame.awayTeam?.team.logo        )    }        private func getQuarter(_ game: APIGame) -> String? {        if game.isFinal { return "Final" }        guard game.isLive else { return nil }                switch selectedSport {  // Use local selectedSport        case .nba: return game.period > 4 ? "OT" : "Q\(game.period)"        case .nfl: return ["1st", "2nd", "3rd", "4th", "OT"][min(game.period - 1, 4)]        case .mlb:            if let detail = game.status.type.shortDetail {                if detail.contains("Top") { return "Top \(game.period)" }                if detail.contains("Bot") { return "Bot \(game.period)" }            }            return "Inning \(game.period)"        case .nhl: return game.period > 3 ? "OT" : "Period \(game.period)"        }    }        private func extractTime(from dateString: String) -> String {        if let date = ISO8601DateFormatter().date(from: dateString) {            let formatter = DateFormatter()            formatter.timeStyle = .short            return formatter.string(from: date)        }        return "TBD"    }}// Section Headerstruct GamesSectionHeader: View {    let title: String    let count: Int    let isLive: Bool        var body: some View {        HStack {            HStack(spacing: 4) {                if isLive {                    Circle()                        .fill(Color.red)                        .frame(width: 8, height: 8)                }                                Text(title)                    .font(.system(size: 12, weight: .bold))                    .foregroundColor(.white.opacity(0.9))            }                        Spacer()                        Text("\(count)")                .font(.system(size: 11, weight: .medium))                .foregroundColor(.white.opacity(0.7))                .padding(.horizontal, 8)                .padding(.vertical, 2)                .background(Color.white.opacity(0.2))                .cornerRadius(10)        }        .padding(.horizontal, 4)        .padding(.top, 16)        .padding(.bottom, 4)    }}// Last Update Timestruct LastUpdateView: View {    let date: Date        var body: some View {        HStack {            Image(systemName: "arrow.clockwise")                .font(.system(size: 10))            Text("Updated: \(date, style: .time)")                .font(.system(size: 10))        }        .foregroundColor(.white.opacity(0.6))        .padding(.top, 20)    }}// Loading Viewstruct LoadingView: View {    var body: some View {        VStack(spacing: 20) {            ProgressView()                .progressViewStyle(CircularProgressViewStyle(tint: .white))                .scaleEffect(1.5)                        Text("Loading games...")                .font(.system(size: 16, weight: .medium))                .foregroundColor(.white.opacity(0.8))        }        .frame(maxWidth: .infinity, maxHeight: .infinity)    }}// Error Viewstruct ErrorView: View {    let error: String    let retry: () -> Void        var body: some View {        VStack(spacing: 20) {            Image(systemName: "exclamationmark.triangle.fill")                .font(.system(size: 40))                .foregroundColor(.white.opacity(0.7))                        Text("Unable to load games")                .font(.headline)                .foregroundColor(.white)                        Text(error)                .font(.caption)                .foregroundColor(.white.opacity(0.7))                .multilineTextAlignment(.center)                        Button(action: retry) {                Text("Try Again")                    .font(.system(size: 14, weight: .semibold))                    .foregroundColor(.black)                    .padding(.horizontal, 24)                    .padding(.vertical, 10)                    .background(Color.white)                    .cornerRadius(20)            }        }        .padding()        .frame(maxWidth: .infinity, maxHeight: .infinity)    }}// Subview for header - now takes a bindingstruct LiveGameHeaderView: View {    @Binding var selectedSport: Sport  // Local binding, not from viewModel        var body: some View {        VStack(spacing: 12) {            Text("Live Sports")                .font(.system(size: 28, weight: .bold))                                        // Sport Selector - changes local state only            HStack(spacing: 12) {                ForEach(Sport.allCases, id: \.self) { sport in                    SportPill(                        sport: sport,                        isSelected: selectedSport == sport                    ) {                        withAnimation(.easeInOut(duration: 0.2)) {                            selectedSport = sport  // Only changes local state                        }                    }                }            }            .frame(maxWidth: .infinity)        }        .padding(.vertical)    }}